package org.apache.commons.compress.archivers;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.ArchiveInputStream;
import org.apache.commons.compress.archivers.ArchiveStreamFactory;
import org.apache.commons.compress.archivers.ArchiveException;

import java.io.*;

import static org.junit.Assert.*;

public class StepDefs {
    private InputStream inputStream;
    private ArchiveInputStream archiveInputStream;
    private Exception exception;

    @Given("an input stream from the file {string}")
    public void an_input_stream_from_the_file(String filePath) throws IOException {
        this.inputStream = new FileInputStream(filePath);
    }

    @Given("an input stream with 512 bytes that parses as a TAR header but has an invalid checksum")
    public void an_input_stream_with_invalid_tar_header_checksum() throws IOException {
        // Create a TAR header with invalid checksum
        byte[] tarHeader = new byte[512];
        // Fill with dummy data and an invalid checksum
        String fileName = "test.txt";
        System.arraycopy(fileName.getBytes(), 0, tarHeader, 0, fileName.length());
        // Set mode to 0100644 (file with specific permissions)
        String mode = "100644 ";
        System.arraycopy(mode.getBytes(), 0, tarHeader, 100, mode.length());
        // Set an invalid checksum
        String invalidChecksum = "000000";  // Invalid checksum
        System.arraycopy(invalidChecksum.getBytes(), 0, tarHeader, 148, 6);

        this.inputStream = new ByteArrayInputStream(tarHeader);
    }

    @When("I attempt to create an archive input stream from the input stream")
    public void i_attempt_to_create_an_archive_input_stream() {
        try {
            ArchiveStreamFactory factory = new ArchiveStreamFactory();
            archiveInputStream = factory.createArchiveInputStream(inputStream);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("an ArchiveException should be thrown")
    public void an_archive_exception_should_be_thrown() {
        assertNotNull("Expected an ArchiveException to be thrown", exception);
        assertTrue("Expected an ArchiveException", exception instanceof ArchiveException);
    }

    @Then("the exception message should start with {string}")
    public void the_exception_message_should_start_with(String expectedStart) {
        assertNotNull("Exception should not be null", exception);
        assertTrue("Exception message should start with '" + expectedStart + "'", 
                   exception.getMessage().startsWith(expectedStart));
    }
}
